mapper.select:
SELECT B1.* FROM ( SELECT A1.* , ROW_NUMBER() OVER(ORDER BY A1.destroyApprovalDt DESC, A1.objectNo) AS PAGEINDEX FROM ( SELECT req.REQUEST_NO AS requestNo , reqMapping.OBJECT_NO AS objectNo , req.OBJECT_TYPE AS objectType , FN_GET_CD_NM('productionObjectType', req.OBJECT_TYPE, 'ko') AS objectTypeNm , reqMapping.REV_NO AS revNo , reqMapping.OBJECT_CLASS_CD2 AS objectClassCd2 , reqMapping.OBJECT_CLASS_NM2 AS objectClassNm2 , reqMapping.PRODUCT_CD AS productCd , COALESCE(reqMapping.PRODUCT_CD, '') AS productNm , reqMapping.Object_Nm AS objectNm , req.business_area_cd AS businessAreaCd , FN_GET_CD_NM('businessAreaCd', req.business_area_cd, 'ko') AS businessAreaNm , req.INSERT_USER_CD AS requestUserCd , (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = req.INSERT_USER_CD) AS requestUserNm , destroyReqDetail.ACTUAL_USER_CD AS destroyRequestUserCd , (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = destroyReqDetail.ACTUAL_USER_CD) AS destroyRequestUserNm , destroyAppDetail.ACTUAL_USER_CD AS destroyApprovalUserCd , (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = destroyAppDetail.ACTUAL_USER_CD) AS destroyApprovalUserNm , destroyAppDetail.ACTION_DT AS destroyApprovalDt , destroyMapping.CURRENT_COUNT AS currentCount FROM DOCS_REQUEST req INNER JOIN DOCS_REQUEST_MAPPING reqMapping ON reqMapping.REQUEST_NO = req.REQUEST_NO INNER JOIN ( SELECT DISTINCT ON (OBJECT_ID, DESTROY_REQUEST_NO) OBJECT_ID, DESTROY_REQUEST_NO, REQUEST_NO, CURRENT_COUNT FROM DOCS_DESTROY_REQUEST_MAPPING WHERE DESTROY_REQUEST_NO IN (SELECT DESTROY_REQUEST_NO FROM DOCS_DESTROY_REQUEST WHERE STATUS_CD = 'APPROVAL') ORDER BY OBJECT_ID, DESTROY_REQUEST_NO, REQUEST_NO DESC ) destroyMapping ON reqMapping.REQUEST_NO = destroyMapping.REQUEST_NO AND reqMapping.OBJECT_ID = destroyMapping.OBJECT_ID INNER JOIN DOCS_DESTROY_REQUEST destroy ON destroy.DESTROY_REQUEST_NO = destroyMapping.DESTROY_REQUEST_NO INNER JOIN DOCS_DESTROY_REQUEST_DETAIL destroyReqDetail ON destroyReqDetail.DESTROY_REQUEST_NO = destroy.DESTROY_REQUEST_NO AND destroyReqDetail.APPROVAL_STATUS_CD = 'REQUEST' INNER JOIN DOCS_DESTROY_REQUEST_DETAIL destroyAppDetail ON destroyAppDetail.DESTROY_REQUEST_NO = destroy.DESTROY_REQUEST_NO AND destroyAppDetail.APPROVAL_STATUS_CD = 'APPROVAL' WHERE req.REQUEST_TYPE = 'PRODUCT' AND destroy.STATUS_CD = 'APPROVAL'
AND reqMapping.OBJECT_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND req.OBJECT_TYPE = #{objectType}
AND reqMapping.OBJECT_CLASS_CD2 = #{objectClassCd2}
AND destroyReqDetail.ACTUAL_USER_CD = #{destroyRequestUserCd}
AND destroyAppDetail.ACTION_DT BETWEEN TO_DATE(#{disposalStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{disposalEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
ORDER BY destroyAppDetail.ACTION_DT DESC, reqMapping.OBJECT_NO
ORDER BY ${sortColumn} ${order}
) A1 WHERE 1=1
AND PAGEINDEX <= #{end}
) B1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(objectNo) AS TOTAL_COUNT FROM ( SELECT req.REQUEST_NO AS requestNo , reqMapping.OBJECT_NO AS objectNo , req.OBJECT_TYPE AS objectType , FN_GET_CD_NM('productionObjectType', req.OBJECT_TYPE, 'ko') AS objectTypeNm , reqMapping.REV_NO AS revNo , reqMapping.OBJECT_CLASS_CD2 AS objectClassCd2 , reqMapping.OBJECT_CLASS_NM2 AS objectClassNm2 , reqMapping.PRODUCT_CD AS productCd , COALESCE(reqMapping.PRODUCT_CD, '') AS productNm , reqMapping.Object_Nm AS objectNm , req.business_area_cd AS businessAreaCd , FN_GET_CD_NM('businessAreaCd', req.business_area_cd, 'ko') AS businessAreaNm , req.INSERT_USER_CD AS requestUserCd , (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = req.INSERT_USER_CD) AS requestUserNm , destroyReqDetail.ACTUAL_USER_CD AS destroyRequestUserCd , (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = destroyReqDetail.ACTUAL_USER_CD) AS destroyRequestUserNm , destroyAppDetail.ACTUAL_USER_CD AS destroyApprovalUserCd , (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = destroyAppDetail.ACTUAL_USER_CD) AS destroyApprovalUserNm , destroyAppDetail.ACTION_DT AS destroyApprovalDt , destroyMapping.CURRENT_COUNT AS currentCount FROM DOCS_REQUEST req INNER JOIN DOCS_REQUEST_MAPPING reqMapping ON reqMapping.REQUEST_NO = req.REQUEST_NO INNER JOIN ( SELECT DISTINCT ON (OBJECT_ID, DESTROY_REQUEST_NO) OBJECT_ID, DESTROY_REQUEST_NO, REQUEST_NO, CURRENT_COUNT FROM DOCS_DESTROY_REQUEST_MAPPING WHERE DESTROY_REQUEST_NO IN (SELECT DESTROY_REQUEST_NO FROM DOCS_DESTROY_REQUEST WHERE STATUS_CD = 'APPROVAL') ORDER BY OBJECT_ID, DESTROY_REQUEST_NO, REQUEST_NO DESC ) destroyMapping ON reqMapping.REQUEST_NO = destroyMapping.REQUEST_NO AND reqMapping.OBJECT_ID = destroyMapping.OBJECT_ID INNER JOIN DOCS_DESTROY_REQUEST destroy ON destroy.DESTROY_REQUEST_NO = destroyMapping.DESTROY_REQUEST_NO INNER JOIN DOCS_DESTROY_REQUEST_DETAIL destroyReqDetail ON destroyReqDetail.DESTROY_REQUEST_NO = destroy.DESTROY_REQUEST_NO AND destroyReqDetail.APPROVAL_STATUS_CD = 'REQUEST' INNER JOIN DOCS_DESTROY_REQUEST_DETAIL destroyAppDetail ON destroyAppDetail.DESTROY_REQUEST_NO = destroy.DESTROY_REQUEST_NO AND destroyAppDetail.APPROVAL_STATUS_CD = 'APPROVAL' WHERE req.REQUEST_TYPE = 'PRODUCT' AND destroy.STATUS_CD = 'APPROVAL'
AND reqMapping.OBJECT_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND req.OBJECT_TYPE = #{objectType}
AND reqMapping.OBJECT_CLASS_CD2 = #{objectClassCd2}
AND destroyReqDetail.ACTUAL_USER_CD = #{destroyRequestUserCd}
AND destroyAppDetail.ACTION_DT BETWEEN TO_DATE(#{disposalStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{disposalEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
) A1
